pub const fn deployment_info(chain_id: u64) -> Option<(Address, Option<u64>)> {
    match chain_id {
        11155111u64 => Some((
            ::alloy_primitives::address!("0x86dcd3293C53Cf8EFd7303B57beb2a3F671dDE98"),
            None,
        )),
        _ => None,
    }
}
